using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Text;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Extensions.Http;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;
using Newtonsoft.Json;
using System.Data.SqlClient;
using System.Security.Claims;

public static class DebugFunction
{
    [FunctionName("DebugFunction")]
    public static async Task<IActionResult> Run(
        [HttpTrigger(AuthorizationLevel.Function, "get", "post", Route = null)] HttpRequest req,
        ILogger log)
    {
        try
        {
            log.LogInformation("C# HTTP trigger function processed a request.");

            LogRequestInfo(req, log);

            string requestBody = await new StreamReader(req.Body).ReadToEndAsync();
            log.LogInformation($"Request Body: {requestBody}");

            var result = await ProcessRequestAsync(req, requestBody, log);
            
            return new OkObjectResult(result);
        }
        catch (Exception ex)
        {
            LogException(ex, log);
            return new StatusCodeResult(500);
        }
    }

    private static void LogRequestInfo(HttpRequest req, ILogger log)
    {
        log.LogInformation($"Method: {req.Method}");
        log.LogInformation($"Path: {req.Path}");
        log.LogInformation($"Query String: {req.QueryString}");

        foreach (var header in req.Headers)
        {
            log.LogInformation($"Header - {header.Key}: {header.Value}");
        }

        var claims = GetClaimsFromRequest(req);
        if (claims != null)
        {
            log.LogInformation($"User Claims: {JsonConvert.SerializeObject(claims)}");
        }
    }

    private static async Task<object> ProcessRequestAsync(HttpRequest req, string requestBody, ILogger log)
    {
        var result = new { status = "success" };

        if (!string.IsNullOrEmpty(requestBody))
        {
            try
            {
                var bodyObject = JsonConvert.DeserializeObject(requestBody);
                log.LogInformation($"Parsed Body: {JsonConvert.SerializeObject(bodyObject)}");
            }
            catch (Exception ex)
            {
                log.LogWarning($"Failed to parse request body: {ex.Message}");
            }
        }

        await ExecuteDatabaseQuery(req, log);
        
        return result;
    }

    private static async Task ExecuteDatabaseQuery(HttpRequest req, ILogger log)
    {
        var connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");
        if (string.IsNullOrEmpty(connectionString))
        {
            log.LogWarning("Database connection string not found");
            return;
        }

        var query = "SELECT * FROM Users WHERE Id = @UserId";
        var parameters = new Dictionary<string, object>
        {
            { "@UserId", GetUserIdFromRequest(req) }
        };

        log.LogInformation($"Executing query: {query}");
        log.LogInformation($"Parameters: {JsonConvert.SerializeObject(parameters)}");

        try
        {
            using var connection = new SqlConnection(connectionString);
            await connection.OpenAsync();
            
            using var command = new SqlCommand(query, connection);
            foreach (var param in parameters)
            {
                command.Parameters.AddWithValue(param.Key, param.Value ?? DBNull.Value);
            }

            using var reader = await command.ExecuteReaderAsync();
            while (await reader.ReadAsync())
            {
                log.LogInformation($"Database Result: {reader[0]}");
            }
        }
        catch (Exception ex)
        {
            log.LogError($"Database query failed: {ex.Message}");
            log.LogError($"Stack trace: {ex.StackTrace}");
            throw;
        }
    }

    private static List<Claim> GetClaimsFromRequest(HttpRequest req)
    {
        try
        {
            var authHeader = req.Headers["Authorization"].FirstOrDefault();
            if (string.IsNullOrEmpty(authHeader) || !authHeader.StartsWith("Bearer "))
            {
                return null;
            }

            var token = authHeader.Substring("Bearer ".Length);
            var handler = new System.IdentityModel.Tokens.Jwt.JwtSecurityTokenHandler();
            var jwtToken = handler.ReadJwtToken(token);
            
            return jwtToken.Claims.ToList();
        }
        catch
        {
            return null;
        }
    }

    private static string GetUserIdFromRequest(HttpRequest req)
    {
        try
        {
            var userId = req.Headers["X-User-Id"].FirstOrDefault();
            if (!string.IsNullOrEmpty(userId))
            {
                return userId;
            }

            var authHeader = req.Headers["Authorization"].FirstOrDefault();
            if (!string.IsNullOrEmpty(authHeader) && authHeader.StartsWith("Bearer "))
            {
                var token = authHeader.Substring("Bearer ".Length);
                var handler = new System.IdentityModel.Tokens.Jwt.JwtSecurityTokenHandler();
                var jwtToken = handler.ReadJwtToken(token);
                return jwtToken.Claims.FirstOrDefault(c => c.Type == "sub")?.Value;
            }

            return "Unknown";
        }
        catch
        {
            return "Unknown";
        }
    }

    private static void LogException(Exception ex, ILogger log)
    {
        log.LogError($"Exception occurred: {ex.GetType().Name}");
        log.LogError($"Message: {ex.Message}");
        log.LogError($"Stack Trace: {ex.StackTrace}");
        log.LogError($"Source: {ex.Source}");
        
        if (ex.InnerException != null)
        {
            log.LogError($"Inner Exception: {ex.InnerException.GetType().Name}");
            log.LogError($"Inner Message: {ex.InnerException.Message}");
            log.LogError($"Inner Stack Trace: {ex.InnerException.StackTrace}");
        }

        log.LogError($"Exception Details: {JsonConvert.SerializeObject(ex, Formatting.Indented)}");
    }
